const error = $input.first().json;
const wfName = error.workflow?.name || 'Unknown';
const wfId = error.workflow?.id || '?';
const nodeName = error.execution?.error?.node?.name || 'Unknown node';
const errorMsg = error.execution?.error?.message || 'No error message';
const executionId = error.execution?.id || '?';
const ts = new Date().toLocaleString('en-US', { timeZone: 'America/Los_Angeles' });

const text = `:rotating_light: *Workflow Error*\n` +
  `*Workflow:* ${wfName} (${wfId})\n` +
  `*Node:* ${nodeName}\n` +
  `*Error:* ${errorMsg}\n` +
  `*Execution:* ${executionId}\n` +
  `*Time:* ${ts}`;

return [{ json: { text, channel: 'C0ALVM4PAE7' } }];
